#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
KIS 스마트머니 레이더 — 단독 실행 파일
=======================================
실행 후 자동으로 브라우저가 열립니다.
종료: 이 창을 닫거나 Ctrl+C
"""

import os, sys, time, json, base64, threading, webbrowser
import requests
from flask import Flask, request, jsonify, Response
from flask_cors import CORS

# ── HTML (내장) ────────────────────────────────────────────
_HTML_B64 = ""

def get_html() -> str:
    return base64.b64decode(_HTML_B64).decode("utf-8")

# ── Flask 앱 ──────────────────────────────────────────────
app  = Flask(__name__)
CORS(app)

KIS_REAL = "https://openapi.koreainvestment.com:9443"
KIS_DEMO = "https://openapivts.koreainvestment.com:9443"

_token_cache = {}   # (appkey, env) → {token, expires_at}

def base_url(env): return KIS_REAL if env == "prod" else KIS_DEMO

# ── 메인 페이지 ───────────────────────────────────────────
@app.route("/")
def index():
    return Response(get_html(), mimetype="text/html; charset=utf-8")

# ── 헬스체크 ──────────────────────────────────────────────
@app.route("/health")
def health():
    return jsonify({"status": "ok", "version": "2.0"})

# ── 토큰 발급 ─────────────────────────────────────────────
@app.route("/api/token", methods=["POST"])
def issue_token():
    body      = request.get_json() or {}
    appkey    = body.get("appkey",    "").strip()
    appsecret = body.get("appsecret", "").strip()
    env       = body.get("env",       "prod")

    if not appkey or not appsecret:
        return jsonify({"error": "appkey / appsecret 필요"}), 400

    ck = (appkey, env)
    cached = _token_cache.get(ck)
    if cached and cached["expires_at"] - time.time() > 300:
        return jsonify({
            "access_token": cached["token"],
            "expires_in":   int(cached["expires_at"] - time.time()),
            "cached": True
        })

    try:
        resp = requests.post(
            base_url(env) + "/oauth2/tokenP",
            json={"grant_type":"client_credentials","appkey":appkey,"appsecret":appsecret},
            timeout=12
        )
        data = resp.json()
    except Exception as e:
        return jsonify({"error": str(e)}), 502

    if resp.status_code != 200 or data.get("error_code"):
        return jsonify(data), resp.status_code

    exp = int(data.get("expires_in", 86400))
    _token_cache[ck] = {"token": data["access_token"], "expires_at": time.time() + exp}
    return jsonify(data)

# ── 상위 순매수 종목 ──────────────────────────────────────
@app.route("/api/top-buys")
def top_buys():
    env       = request.args.get("env",       "prod")
    token     = request.args.get("token",     "")
    appkey    = request.args.get("appkey",    "")
    appsecret = request.args.get("appsecret", "")
    market    = request.args.get("market",    "J")
    top_n     = int(request.args.get("top_n", 30))

    if not token:
        return jsonify({"error": "token 필수"}), 400

    hdrs = {
        "Content-Type":  "application/json",
        "authorization": f"Bearer {token}",
        "appkey":        appkey,
        "appsecret":     appsecret,
        "custtype":      "P",
    }

    # 1차: 가집계 랭킹 API
    try:
        r = requests.get(
            base_url(env) + "/uapi/domestic-stock/v1/quotations/foreign-institution-total",
            headers={**hdrs, "tr_id": "FHPST01710000"},
            params={
                "FID_COND_MRKT_DIV_CODE": market, "FID_COND_SCR_DIV_CODE": "16448",
                "FID_INPUT_ISCD": "0001", "FID_DIV_CLS_CODE": "0",
                "FID_RANK_SORT_CLS_CODE": "0", "FID_ETC_CLS_CODE": "0",
            }, timeout=12)
        d = r.json()
        if d.get("rt_cd") == "0" and d.get("output"):
            stocks = [{
                "code":        row.get("mksc_shrn_iscd") or row.get("shtn_iscd",""),
                "name":        row.get("hts_kor_isnm","—"),
                "foreignBuy":  round(float(row.get("frgn_ntby_tr_pbmn") or 0)/1e8,1),
                "instBuy":     round(float(row.get("orgn_ntby_tr_pbmn") or 0)/1e8,1),
                "indivBuy":    round(float(row.get("prsn_ntby_tr_pbmn") or 0)/1e8,1),
                "pensionBuy":  0,
                "price":       int(row.get("stck_prpr") or 0),
                "change":      float(row.get("prdy_ctrt") or 0),
                "foreignRate": float(row.get("hts_frgn_ehrt") or 0),
                "vol":         int(row.get("acml_vol") or 0),
            } for row in d["output"][:top_n]]
            return jsonify({"source":"ranking","data":stocks})
    except Exception as e:
        print(f"[WARN] ranking API: {e}")

    # 2차: 종목별 개별 조회 fallback
    WATCHLIST = [
        ("005930","삼성전자"),("000660","SK하이닉스"),("035420","NAVER"),
        ("005380","현대차"),  ("051910","LG화학"),    ("006400","삼성SDI"),
        ("035720","카카오"),  ("068270","셀트리온"),  ("373220","LG에너지솔루션"),
        ("207940","삼성바이오로직스"),("096770","SK이노베이션"),("105560","KB금융"),
        ("055550","신한지주"),("003670","포스코홀딩스"),("066570","LG전자"),
        ("028260","삼성물산"),("259960","크래프톤"),  ("011200","HMM"),
        ("009150","삼성전기"),("323410","카카오뱅크"),
    ]
    inv_url = base_url(env) + "/uapi/domestic-stock/v1/quotations/inquire-investor"
    prc_url = base_url(env) + "/uapi/domestic-stock/v1/quotations/inquire-price"
    stocks  = []
    for code, name in WATCHLIST[:top_n]:
        try:
            ri = requests.get(inv_url, headers={**hdrs,"tr_id":"FHKST01010900"},
                params={"FID_COND_MRKT_DIV_CODE":market,"FID_INPUT_ISCD":code}, timeout=8)
            rp = requests.get(prc_url, headers={**hdrs,"tr_id":"FHKST01010100"},
                params={"FID_COND_MRKT_DIV_CODE":market,"FID_INPUT_ISCD":code}, timeout=8)
            di, dp = ri.json(), rp.json()
            if di.get("rt_cd")!="0" or dp.get("rt_cd")!="0": continue
            row = di.get("output") or {}
            if isinstance(row, list): row = row[0] if row else {}
            stocks.append({
                "code":code,"name":name,
                "foreignBuy": round(float(row.get("frgn_ntby_tr_pbmn") or row.get("frgn_ntby_qty") or 0)/1e8,1),
                "instBuy":    round(float(row.get("orgn_ntby_tr_pbmn") or row.get("inst_ntby_qty")  or 0)/1e8,1),
                "pensionBuy": round(float(row.get("pgtr_ntby_tr_pbmn") or 0)/1e8,1),
                "indivBuy":   round(float(row.get("prsn_ntby_tr_pbmn") or row.get("prsn_ntby_qty")  or 0)/1e8,1),
                "price":      int(dp["output"].get("stck_prpr") or 0),
                "change":     float(dp["output"].get("prdy_ctrt") or 0),
                "foreignRate":float(dp["output"].get("hts_frgn_ehrt") or 0),
                "vol":        int(dp["output"].get("acml_vol") or 0),
                "mktCap":     round(float(dp["output"].get("hts_avls") or 0)/1e8, 0),
            })
            time.sleep(0.08)
        except Exception as e:
            print(f"[WARN] {code}: {e}")
    return jsonify({"source":"per_stock","data":stocks})


# ══════════════════════════════════════════════════════════
#  실행 진입점
# ══════════════════════════════════════════════════════════
PORT = 5000

def open_browser():
    time.sleep(1.5)
    webbrowser.open(f"http://localhost:{PORT}")

if __name__ == "__main__":
    # Windows exe 환경에서 콘솔창 타이틀 설정
    if sys.platform == "win32":
        os.system("title KIS 스마트머니 레이더")

    print()
    print("=" * 58)
    print("  📡  KIS 스마트머니 레이더  v2.0")
    print("=" * 58)
    print(f"  ✅  서버 시작: http://localhost:{PORT}")
    print(f"  🌐  브라우저가 자동으로 열립니다...")
    print(f"  ⛔  종료하려면 이 창을 닫으세요")
    print("=" * 58)
    print()

    # 브라우저 자동 오픈 (별도 스레드)
    threading.Thread(target=open_browser, daemon=True).start()

    # Flask 서버 실행
    app.run(host="127.0.0.1", port=PORT, debug=False, use_reloader=False)
